import React, { useState } from 'react';
import '../styles/AdminPage.css';

export default function AdminPage() {
  const [accounts, setAccounts] = useState([]);
  const [filter, setFilter] = useState('all');

  const handleDeleteAccount = (id) => {
    if (window.confirm('Are you sure you want to delete this account?')) {
      setAccounts(accounts.filter((account) => account.id !== id));
    }
  };

  const handleBanAccount = (id) => {
    setAccounts(
      accounts.map((account) =>
        account.id === id
          ? { ...account, status: account.status === 'banned' ? 'active' : 'banned' }
          : account
      )
    );
  };

  const filteredAccounts = accounts.filter((account) => {
    if (filter === 'all') return true;
    return account.status === filter;
  });

  return (
    <div className="admin-container">
      <div className="admin-header">
        <h1>Admin Dashboard</h1>
        <p>Manage user accounts</p>
      </div>

      <div className="admin-filter">
        <button
          className={`filter-btn ${filter === 'all' ? 'active' : ''}`}
          onClick={() => setFilter('all')}
        >
          All Accounts ({accounts.length})
        </button>
        <button
          className={`filter-btn ${filter === 'active' ? 'active' : ''}`}
          onClick={() => setFilter('active')}
        >
          Active ({accounts.filter((a) => a.status === 'active').length})
        </button>
        <button
          className={`filter-btn ${filter === 'banned' ? 'active' : ''}`}
          onClick={() => setFilter('banned')}
        >
          Banned ({accounts.filter((a) => a.status === 'banned').length})
        </button>
      </div>

      {filteredAccounts.length === 0 ? (
        <div className="no-accounts">
          <p>No accounts to display</p>
        </div>
      ) : (
        <div className="accounts-table">
          <table>
            <thead>
              <tr>
                <th>ID</th>
                <th>Email</th>
                <th>Name</th>
                <th>Status</th>
                <th>Joined</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {filteredAccounts.map((account) => (
                <tr key={account.id}>
                  <td>{account.id}</td>
                  <td>{account.email}</td>
                  <td>{account.name}</td>
                  <td>
                    <span className={`status-badge ${account.status}`}>
                      {account.status.charAt(0).toUpperCase() + account.status.slice(1)}
                    </span>
                  </td>
                  <td>{account.joinDate}</td>
                  <td>
                    <div className="action-buttons">
                      <button
                        className={`btn-ban ${account.status === 'banned' ? 'unban' : ''}`}
                        onClick={() => handleBanAccount(account.id)}
                      >
                        {account.status === 'banned' ? 'Unban' : 'Ban'}
                      </button>
                      <button
                        className="btn-delete"
                        onClick={() => handleDeleteAccount(account.id)}
                      >
                        Delete
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
